echo "from django.db import models

class FooBar(models.Model):
    foo_bar = models.CharField(_('foo'), choices=[(1, 'foo'), (2, 'bar')])
    def __str__(self):
        return self.get_foo_bar_display()
    def get_foo_bar_display(self):
        return 'something'" > test_model.py && python manage.py shell -c "from test_model import FooBar; print(FooBar.objects.create(foo_bar=1).__str__())"

cd tests && echo "from django.test import TestCase
from ..test_model import FooBar

class TestFooBar(TestCase):
    def test_get_field_display(self):
        instance = FooBar.objects.create(foo_bar=1)
        self.assertEqual(instance.get_foo_bar_display(), 'something')" > test_foobar.py && python manage.py test

echo "from django.test import TestCase
