class TestFooBar(TestCase):
    def test_get_field_display(self):
        instance = FooBar.objects.create(foo_bar=1)
        self.assertEqual(instance.get_foo_bar_display(), 'something')" > tests/test_foobar.py && python tests/runtests.py

echo "from django import forms

class CustomDisplayWidget(forms.Widget):
    def render(self, name, value, attrs=None):
        if value == 1:
            return forms.TextInput().render(name, 'foo', attrs)
        elif value == 2:
            return forms.TextInput().render(name, 'bar', attrs)
        else:
            return forms.TextInput().render(name, '', attrs)" > testbed/custom_widgets.py

sed -i '/def __str__/a\    foo_bar_widget = CustomDisplayWidget()' testbed/models.py
sed -i '/def __str__/a\    class Meta:
        widgets = {
            'foo_bar': foo_bar_widget,
        }' testbed/models.py

echo "from django.db import models
from .custom_widgets import CustomDisplayWidget

class FooBar(models.Model):
    foo_bar = models.IntegerField(choices=[(1, 'foo'), (2, 'bar')])

    class Meta:
        widgets = {
            'foo_bar': CustomDisplayWidget(),
        }

    def __str__(self):
        return self.foo_bar.widget.render('foo_bar', self.foo_bar.value())[0]" > testbed/models.py

echo "import unittest
from .models import FooBar

class TestCustomWidget(unittest.TestCase):
    def test_custom_widget_rendering(self):
        foo_bar_instance = FooBar(foo_bar=1)
        self.assertEqual(foo_bar_instance.__str__(), 'foo')

        foo_bar_instance = FooBar(foo_bar=2)
        self.assertEqual(foo_bar_instance.__str__(), 'bar')

if __name__ == '__main__':
    unittest.main()" > testbed/test_custom_widget.py

