echo "from django.db import models

class CustomProductMetaDataTypeManager(models.Manager):
    def get_queryset(self):
        return super().get_queryset().filter(filterable=True)

class ProductMetaDataType(models.Model):
    label = models.CharField(max_length=255, unique=True, blank=False, null=False)
    filterable = models.BooleanField(default=False, verbose_name=_('filterable'))
    objects = CustomProductMetaDataTypeManager()

    class Meta:
        app_label = "adminpricing"
        verbose_name = _('product meta data type')
        verbose_name_plural = _('product meta data types')

    def __str__(self):
        return self.label" > /testbed/adminpricing/models.py.tmp && mv /testbed/adminpricing/models.py.tmp /testbed/adminpricing/models.py

